#!/usr/bin/env node
// Generates .claude/skills/CATALOG.md from skill frontmatter.
// Auto-generated file — never hand-edit CATALOG.md; run `just skills-catalog`.
import { writeFileSync } from 'node:fs';
import { CATALOG_PATH, listSkills, loadConfig } from './skill-lib.mjs';

const cfg = loadConfig();
const skills = listSkills();

const trunc = (s, n = 160) => {
  const t = (s || '').replace(/\s+/g, ' ').trim();
  return t.length > n ? t.slice(0, n - 1) + '…' : t;
};

const firstParty = skills.filter((s) => s.firstParty);
const external = skills.filter((s) => s.isSymlink);

const row = (s) => {
  const fm = s.fm;
  const status = fm.status || (cfg.grandfathered.includes(s.dir) ? '_legacy_' : '—');
  const owner = fm.owner || '—';
  const links = [
    fm.supersedes ? `supersedes \`${fm.supersedes}\`` : null,
    Array.isArray(fm.related) && fm.related.length ? `related: ${fm.related.map((r) => `\`${r}\``).join(', ')}` : null,
    fm['superseded-by'] ? `superseded-by \`${fm['superseded-by']}\`` : null,
  ].filter(Boolean).join('; ') || '—';
  return `| \`${fm.name || s.dir}\` | ${status} | ${owner} | ${trunc(fm.description)} | ${links} |`;
};

const lines = [];
lines.push('<!-- GENERATED by .claude/tools/gen-skills-catalog.mjs — DO NOT EDIT BY HAND. Run `just skills-catalog`. -->');
lines.push('# Skills Catalog');
lines.push('');
lines.push('Auto-generated inventory of dotCMS skills. **Check here before creating a new skill** — if something close exists, extend it or mark yours `related`, don\'t fork. See [CONTRIBUTING.md](CONTRIBUTING.md).');
lines.push('');
lines.push(`_${firstParty.length} first-party · ${external.length} external (symlinked)._`);
lines.push('');
lines.push('## First-party skills (`dot-*`)');
lines.push('');
lines.push('| Name | Status | Owner | Description | Links |');
lines.push('| --- | --- | --- | --- | --- |');
for (const s of firstParty) lines.push(row(s));
lines.push('');
lines.push('## External skills (symlinked, not governed here)');
lines.push('');
lines.push('| Name | Source |');
lines.push('| --- | --- |');
for (const s of external) lines.push(`| \`${s.fm.name || s.dir}\` | \`.agents/skills/${s.dir}\` |`);
lines.push('');

writeFileSync(CATALOG_PATH, lines.join('\n'));
console.log(`Wrote ${CATALOG_PATH} (${firstParty.length} first-party, ${external.length} external).`);
